def inject_svg(filepath, svgs_list):
    try:
        with open(filepath, 'r') as f:
            content = f.read()
        
        # Clean placeholders from previous run
        content = re.sub(r',\s*\{\s*id:\s*[\'"]svg-[^\}]+\}\s*\}', '', content, flags=re.DOTALL)
        
        injected = ""
        import random
        for caption, svg in svgs_list:
            rid = random.randint(100000, 999999)
            injected += f",\n    {{ id: 'svg-real-2_{rid}', type: 'svg', data: {{ svg: '{svg}', caption: \"{caption}\" }} }}"
        
        content = re.sub(r'\n  ],\n  recall:', f'{injected}\n  ],\n  recall:', content)
        with open(filepath, 'w') as f:
            f.write(content)
    except FileNotFoundError:
        pass

for subtopic, svgs in svgs_6.items():
    inject_svg(f"src/data/seedNotes/physics/note_physics_2_6_{subtopic}.js", svgs)

